# ===========================================================================
#  EMBEDDED PROTOBUF DESCRIPTORS (base64 of a FileDescriptorSet, zlib'd)
#  -- generated once from the game's recovered .proto files; needed so this
#  script can build/parse gRPC messages WITHOUT any generated _pb2 stubs.
# ===========================================================================
_DESCRIPTORS_B64 = ""


def _build_pool():
    raw = zlib.decompress(base64.b64decode(_DESCRIPTORS_B64))
    fds = descriptor_pb2.FileDescriptorSet()
    fds.ParseFromString(raw)
    pool = descriptor_pool.DescriptorPool()
    files = {f.name: f for f in fds.file}
    done = set()

    def add(name, stack):
        if name in done or name not in files or name in stack:
            return
        stack.add(name)
        f = files[name]
        for dep in f.dependency:
            add(dep, stack)
        try:
            pool.Add(f)
        except Exception:
            pass
        done.add(name)
        stack.discard(name)

    for n in list(files):
        add(n, set())
    return pool


POOL = _build_pool()


def msgcls(desc):
    try:
        return message_factory.GetMessageClass(desc)
    except AttributeError:
        return message_factory.MessageFactory(POOL).GetPrototype(desc)


RoomIn  = msgcls(POOL.FindMessageTypeByName("service.multiplay.RoomInboundMessage"))
RoomOut = msgcls(POOL.FindMessageTypeByName("service.multiplay.RoomOutboundMessage"))
IngIn   = msgcls(POOL.FindMessageTypeByName("service.multiplay.IngameInboundMessage"))
IngOut  = msgcls(POOL.FindMessageTypeByName("service.multiplay.IngameOutboundMessage"))


class FarmError(Exception):
    """Structured farm failure for API consumers (not a process exit)."""

    def __init__(self, code: str, detail=None):
        self.code = code
        self.detail = detail
        super().__init__(code)


# ------------------------------- login -------------------------------------
def login():
    lc = copy.deepcopy(DEFAULT_LC); lc["devsisters_id"] = ""
    d = requests.post(f"{AUTH_HOST}/v3/login/devsisters", headers=HEADERS,
                      json={"email": EMAIL, "password": PASSWORD,
                            "oven_access_token": "", "lc": lc}, timeout=20).json()
    if d.get("code") != 20000:
        print("LOGIN FAILED:", json.dumps(d, ensure_ascii=False)[:400])
        raise FarmError("login_failed", d)
    return d["game_access_token"], d["member"]["mid"], lc


